files.css:
table { border-collapse: collapse; font-family: sans-serif; }
th, td { border: 1px solid #ccc; padding: 0.5rem 1rem; }
th { background: #f1f5f9; }

form { font-family: sans-serif; padding: 1rem; max-width: 280px; }
label { display: block; margin-bottom: 0.25rem; }
input { width: 100%; padding: 0.4rem; }

body { font-family: sans-serif; margin: 0; }
header { background: #2563eb; color: #fff; padding: 1rem; }
header h1 { margin: 0; font-size: 1.25rem; }
main { padding: 1rem; max-width: 320px; }
form label { display: block; margin-bottom: 0.25rem; }
input { width: 100%; padding: 0.4rem; box-sizing: border-box; }
button { margin-top: 0.5rem; padding: 0.45rem 0.85rem; background: #2563eb; color: #fff; border: none; border-radius: 6px; cursor: pointer; }
